Data.data:
body {
  background: linear-gradient(135deg, #0d0d1a 0%, #1a1a2e 50%, #16213e 100%);
  background-attachment: fixed;
  position: relative;
}
body::before {
  content: '';
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-image: radial-gradient(circle at 20% 50%, rgba(74,59,105,0.15) 0%, transparent 50%), radial-gradient(circle at 80% 80%, rgba(201,162,39,0.1) 0%, transparent 40%), radial-gradient(circle at 40% 20%, rgba(74,222,128,0.08) 0%, transparent 35%);
  pointer-events: none;
  z-index: -1;
}
.header {
  background: linear-gradient(180deg, rgba(13,13,26,0.95) 0%, rgba(26,26,46,0.9) 100%);
  border-bottom: 3px solid #c9a227;
  box-shadow: 0 4px 20px rgba(201,162,39,0.3);
}
.brand {
  background: linear-gradient(135deg, #c9a227 0%, #f4d03f 50%, #c9a227 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: 0 0 30px rgba(201,162,39,0.5);
  font-weight: bold;
  letter-spacing: 2px;
}
.menu-item a {
  color: #d1d5db !important;
  transition: all 0.3s ease;
  position: relative;
}
.menu-item a:hover {
  color: #c9a227 !important;
  text-shadow: 0 0 10px rgba(201,162,39,0.8);
}
.post-block {
  background: linear-gradient(145deg, #1e1e32 0%, #2a2a45 100%);
  border: 2px solid #8b7355;
  border-radius: 12px;
  box-shadow: 0 8px 32px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.1);
  position: relative;
  overflow: hidden;
  margin-bottom: 30px;
}
.post-block::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: linear-gradient(45deg, transparent 30%, rgba(201,162,39,0.03) 50%, transparent 70%);
  transform: rotate(45deg);
  pointer-events: none;
}
.post-block:hover {
  border-color: #c9a227;
  box-shadow: 0 8px 32px rgba(0,0,0,0.4), 0 0 20px rgba(201,162,39,0.2), inset 0 1px 0 rgba(255,255,255,0.1);
}
.post-title a {
  color: #f3f4f6 !important;
  transition: all 0.3s ease;
}
.post-title a:hover {
  color: #c9a227 !important;
  text-shadow: 0 0 15px rgba(201,162,39,0.5);
}
.post-meta {
  color: #9ca3af !important;
}
.post-meta a {
  color: #6b5b8a !important;
}
.post-meta a:hover {
  color: #4ade80 !important;
}
.sidebar {
  background: linear-gradient(180deg, #1a1a2e 0%, #16213e 100%);
  border: 2px solid #4a3b69;
  border-radius: 12px;
  box-shadow: 0 4px 20px rgba(0,0,0,0.3);
}
.sidebar-title {
  color: #c9a227 !important;
  border-bottom: 2px solid #4a3b69;
  padding-bottom: 10px;
}
tag-cloud a {
  background: linear-gradient(135deg, #4a3b69 0%, #6b5b8a 100%);
  border: 1px solid #c9a227;
  color: #fff !important;
  border-radius: 20px;
  padding: 4px 12px;
  transition: all 0.3s ease;
}
tag-cloud a:hover {
  background: linear-gradient(135deg, #c9a227 0%, #f4d03f 100%);
  color: #1a1a2e !important;
  box-shadow: 0 0 15px rgba(201,162,39,0.5);
  transform: translateY(-2px);
}
.btn {
  background: linear-gradient(135deg, #4a3b69 0%, #6b5b8a 100%);
  border: 2px solid #c9a227;
  color: #fff;
  border-radius: 8px;
  transition: all 0.3s ease;
}
.btn:hover {
  background: linear-gradient(135deg, #c9a227 0%, #f4d03f 100%);
  color: #1a1a2e;
  box-shadow: 0 0 20px rgba(201,162,39,0.4);
}
.pagination {
  background: linear-gradient(135deg, #1e1e32 0%, #2a2a45 100%);
  border: 2px solid #4a3b69;
  border-radius: 8px;
}
.pagination a,
.pagination span {
  color: #d1d5db !important;
  border-color: #4a3b69 !important;
}
.pagination a:hover {
  background: #4a3b69 !important;
  color: #c9a227 !important;
}
.pagination .current {
  background: #c9a227 !important;
  color: #1a1a2e !important;
  border-color: #c9a227 !important;
}
.footer {
  background: linear-gradient(180deg, #0d0d1a 0%, #1a1a2e 100%);
  border-top: 3px solid #4a3b69;
  color: #9ca3af;
}
.footer a {
  color: #6b5b8a !important;
}
.footer a:hover {
  color: #c9a227 !important;
}
pre,
code {
  background: #0d0d1a !important;
  border: 1px solid #4a3b69;
  border-radius: 6px;
}
code {
  color: #4ade80 !important;
}
pre code {
  color: #d1d5db !important;
}
blockquote {
  background: linear-gradient(90deg, rgba(74,59,105,0.3) 0%, transparent 100%);
  border-left: 4px solid #c9a227;
  color: #d1d5db;
}
a {
  color: #6b5b8a;
  transition: all 0.3s ease;
}
a:hover {
  color: #c9a227;
}
::-webkit-scrollbar {
  width: 10px;
}
::-webkit-scrollbar-track {
  background: #0d0d1a;
}
::-webkit-scrollbar-thumb {
  background: linear-gradient(180deg, #4a3b69 0%, #6b5b8a 100%);
  border-radius: 5px;
  border: 2px solid #0d0d1a;
}
::-webkit-scrollbar-thumb:hover {
  background: linear-gradient(180deg, #c9a227 0%, #f4d03f 100%);
}
::selection {
  background: rgba(201,162,39,0.3);
  color: #fff;
}
.float-animation {
  animation: float 3s ease-in-out infinite;
}
.glow-animation {
  animation: glow 2s ease-in-out infinite;
}
.post-button .btn {
  background: linear-gradient(135deg, rgba(201,162,39,0.2) 0%, rgba(201,162,39,0.1) 100%);
  border-color: #c9a227;
  color: #c9a227;
}
.post-button .btn:hover {
  background: linear-gradient(135deg, #c9a227 0%, #f4d03f 100%);
  color: #1a1a2e;
}
hr {
  border: none;
  height: 2px;
  background: linear-gradient(90deg, transparent 0%, #4a3b69 50%, transparent 100%);
  margin: 30px 0;
}
table {
  background: #1e1e32;
  border: 2px solid #4a3b69;
  border-radius: 8px;
}
th {
  background: #4a3b69;
  color: #c9a227;
}
td {
  border-color: #4a3b69;
  color: #d1d5db;
}
tr:hover {
  background: rgba(74,59,105,0.3);
}
@-moz-keyframes glow {
  0%, 100% {
    box-shadow: 0 0 5px rgba(201,162,39,0.5);
  }
  50% {
    box-shadow: 0 0 20px rgba(201,162,39,0.8), 0 0 40px rgba(201,162,39,0.4);
  }
}
@-webkit-keyframes glow {
  0%, 100% {
    box-shadow: 0 0 5px rgba(201,162,39,0.5);
  }
  50% {
    box-shadow: 0 0 20px rgba(201,162,39,0.8), 0 0 40px rgba(201,162,39,0.4);
  }
}
@-o-keyframes glow {
  0%, 100% {
    box-shadow: 0 0 5px rgba(201,162,39,0.5);
  }
  50% {
    box-shadow: 0 0 20px rgba(201,162,39,0.8), 0 0 40px rgba(201,162,39,0.4);
  }
}
@keyframes glow {
  0%, 100% {
    box-shadow: 0 0 5px rgba(201,162,39,0.5);
  }
  50% {
    box-shadow: 0 0 20px rgba(201,162,39,0.8), 0 0 40px rgba(201,162,39,0.4);
  }
}
@-moz-keyframes float {
  0%, 100% {
    transform: translateY(0px);
  }
  50% {
    transform: translateY(-10px);
  }
}
@-webkit-keyframes float {
  0%, 100% {
    transform: translateY(0px);
  }
  50% {
    transform: translateY(-10px);
  }
}
@-o-keyframes float {
  0%, 100% {
    transform: translateY(0px);
  }
  50% {
    transform: translateY(-10px);
  }
}
@keyframes float {
  0%, 100% {
    transform: translateY(0px);
  }
  50% {
    transform: translateY(-10px);
  }
}
